POST /roteiro/aprovar
Payload: { video_id: uuid, opcao_id: uuid }
Disparado pelo frontend ao aprovar um roteiro.

parameters.jsCode:
// ===================================================================
// NORMALIZAR INPUT — Módulo 02B
// ===================================================================
// Aceita input do Manual Trigger ou do Webhook.
// Saída unificada: { video_id, opcao_id }
// ===================================================================

const item = $input.first().json;
const video_id = item.video_id || (item.body && item.body.video_id) || null;
const opcao_id = item.opcao_id || (item.body && item.body.opcao_id) || null;

if (!video_id || !opcao_id) {
  throw new Error('video_id e opcao_id são obrigatórios.');
}

return [{ json: { video_id, opcao_id } }];

// ===================================================================
// PREPARAR PROMPT ANALISTA — Módulo 02B
// ===================================================================
// Monta prompt para o Claude recalcular campos narrativos
// do Módulo 10 com base nas cenas editadas.
// ===================================================================

const opcao = $('Ler Opção Aprovada').first().json;
const cenas = $('Ler Cenas Editadas').all().map(i => i.json);
const videoId = $('Normalizar Input').first().json.video_id;
const opcaoId = $('Normalizar Input').first().json.opcao_id;

const cenasTexto = cenas.map(c =>
  `Cena ${c.numero} (${c.emocao}, ${c.tipo_cena}): "${c.narracao}" [${c.transicao_entrada}]`
).join('\n');

const systemPrompt = `Você é um analista narrativo. Analise o roteiro abaixo e classifique os campos narrativos. Responda APENAS com JSON válido, sem markdown, sem backticks, sem explicação.

CAMPOS PARA CLASSIFICAR:
- arco_tipo: escalada_linear | revelacao_tardia | degradacao_gradual | falsa_seguranca | loop
- cena_virada: número da cena onde a história muda de direção (string, ex: "4")
- num_revelacoes: quantos elementos novos a história apresenta ao espectador (int)
- encerramento_tipo: pergunta_aberta | convite_sinistro | afirmacao | silencio
- resolucao: aberto | resolvido
- papel_clay: vitima | testemunha | perigo_iminente
- hook_tipo: pergunta | afirmacao | acao | cenario (baseado na cena 1)

Formato JSON exato:
{"arco_tipo": "...", "cena_virada": "...", "num_revelacoes": 0, "encerramento_tipo": "...", "resolucao": "...", "papel_clay": "...", "hook_tipo": "..."}`;

const userMessage = `TÍTULO: ${opcao.titulo || '(sem título)'}
FORMATO: ${opcao.formato || 'shorts'}
SINOPSE: ${opcao.sinopse || '(sem sinopse)'}
TEXTO FINAL: ${opcao.texto_final_tela || '(sem texto)'}

CENAS (${cenas.length}):
${cenasTexto}`;

return [{
  json: {
    _systemPrompt: systemPrompt,
    _userMessage: userMessage,
    _videoId: videoId,
    _opcaoId: opcaoId,
    _opcao: opcao,
    _cenas: cenas
  }
}];

// ===================================================================
// PARSE ANÁLISE + RECOMPOR JSON — Módulo 02B
// ===================================================================
// Parseia campos narrativos do Claude Analista.
// Recompõe roteiro_json final com opção + cenas editadas.
// Calcula num_cenas e duracao_estimada.
// ===================================================================

const response = $input.first().json;
const prev = $('Preparar Prompt Analista').first().json;
const opcao = prev._opcao;
const cenas = prev._cenas;
const videoId = prev._videoId;
const opcaoId = prev._opcaoId;

// Parse dos campos narrativos do Claude
let narrativo = {};
try {
  const text = response.text || response.response || '';
  const clean = text.replace(/```json|```/g, '').trim();
  narrativo = JSON.parse(clean);
} catch (e) {
  // Fallback: valores conservadores
  narrativo = {
    arco_tipo: 'escalada_linear',
    cena_virada: '1',
    num_revelacoes: 1,
    encerramento_tipo: 'aberto',
    resolucao: 'aberto',
    papel_clay: 'vitima',
    hook_tipo: 'acao'
  };
}

// Recompor JSON final do roteiro
const roteiroJson = {
  titulo: opcao.titulo,
  sinopse: opcao.sinopse,
  arco_narrativo: opcao.arco_narrativo,
  tom: opcao.tom,
  formato: opcao.formato,
  caption: opcao.caption,
  descricao_youtube: opcao.descricao_youtube,
  hashtags: opcao.hashtags,
  tags: opcao.tags,
  thumbnail_prompt: opcao.thumbnail_prompt,
  texto_final_tela: opcao.texto_final_tela,
  arco_tipo: narrativo.arco_tipo,
  cena_virada: narrativo.cena_virada,
  num_revelacoes: narrativo.num_revelacoes,
  encerramento_tipo: narrativo.encerramento_tipo,
  resolucao: narrativo.resolucao,
  papel_clay: narrativo.papel_clay,
  cenas: cenas.map(c => ({
    numero: c.numero,
    ordem: c.ordem,
    narracao: c.narracao,
    emocao: c.emocao,
    visual: c.visual,
    tipo_cena: c.tipo_cena,
    movimento: c.movimento,
    som_ambiente: c.som_ambiente,
    efeitos_sonoros: c.efeitos_sonoros,
    duracao_estimada: c.duracao_estimada,
    continuidade: c.continuidade,
    personagem_presente: c.personagem_presente,
    perspectiva: c.perspectiva,
    transicao_entrada: c.transicao_entrada,
    hook_tipo: c.hook_tipo
  }))
};

const numCenas = cenas.length;
const duracaoEstimada = cenas.reduce((sum, c) => sum + (c.duracao_estimada || 4), 0);

return [{
  json: {
    _videoId: videoId,
    _opcaoId: opcaoId,
    _roteiroJson: roteiroJson,
    _narrativo: narrativo,
    _numCenas: numCenas,
    _duracaoEstimada: duracaoEstimada,
    _opcao: opcao
  }
}];

// ===================================================================
// EXECUTAR APROVAÇÃO — Módulo 02B
// ===================================================================
// Executa todas as operações de aprovação via this.helpers.httpRequest:
// 1. PATCH videos — metadados + campos narrativos + modulo_atual='03'
// 2. PATCH cenas — opcao_id = null (desconectar das opções)
// 3. PATCH roteiro_opcoes — status = 'aprovada'
// 4. DELETE roteiro_opcoes rejeitadas (CASCADE limpa cenas)
// ===================================================================

const data = $input.first().json;
const config = $('Configuração').first().json;
const baseUrl = config.SUPABASE_URL;
const apiKey = config.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': apiKey,
  'Authorization': `Bearer ${apiKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const erros = [];

// 1. Atualizar vídeo com metadados + campos narrativos + avançar módulo
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${baseUrl}/rest/v1/videos?id=eq.${data._videoId}`,
    headers,
    body: {
      titulo: data._opcao.titulo,
      caption: data._opcao.caption,
      descricao_youtube: data._opcao.descricao_youtube,
      hashtags: data._opcao.hashtags,
      tags: data._opcao.tags,
      thumbnail_prompt: data._opcao.thumbnail_prompt || null,
      texto_final_tela: data._opcao.texto_final_tela,
      formato: data._opcao.formato,
      sinopse: data._opcao.sinopse,
      tom: data._opcao.tom,
      arco_narrativo: data._opcao.arco_narrativo,
      roteiro_json: data._roteiroJson,
      num_cenas: data._numCenas,
      duracao_estimada: data._duracaoEstimada,
      arco_tipo: data._narrativo.arco_tipo,
      cena_virada: data._narrativo.cena_virada,
      num_revelacoes: data._narrativo.num_revelacoes,
      encerramento_tipo: data._narrativo.encerramento_tipo,
      resolucao: data._narrativo.resolucao,
      papel_clay: data._narrativo.papel_clay,
      modulo_atual: '03',
      status: 'processando'
    }
  });
} catch (e) {
  erros.push(`Atualizar vídeo: ${e.message}`);
}

// 2. Desconectar cenas aprovadas (opcao_id = null)
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${baseUrl}/rest/v1/cenas?opcao_id=eq.${data._opcaoId}`,
    headers,
    body: { opcao_id: null }
  });
} catch (e) {
  erros.push(`Desconectar cenas: ${e.message}`);
}

// 3. Marcar opção como aprovada
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${baseUrl}/rest/v1/roteiro_opcoes?id=eq.${data._opcaoId}`,
    headers,
    body: { status: 'aprovada' }
  });
} catch (e) {
  erros.push(`Marcar aprovada: ${e.message}`);
}

// 4. Deletar opções rejeitadas (CASCADE limpa cenas vinculadas a elas)
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: `${baseUrl}/rest/v1/roteiro_opcoes?video_id=eq.${data._videoId}&id=neq.${data._opcaoId}`,
    headers: {
      'apikey': apiKey,
      'Authorization': `Bearer ${apiKey}`
    }
  });
} catch (e) {
  erros.push(`Deletar rejeitadas: ${e.message}`);
}

// 5. Marcar cenas de texto como aprovadas em todos os módulos
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${baseUrl}/rest/v1/cenas?video_id=eq.${data._videoId}&tipo_cena=eq.texto`,
    headers,
    body: {
      imagem_status: 'aprovada',
      tts_status: 'aprovada',
      efeito_status: 'aprovada',
      video_status: 'aprovada'
    }
  });
} catch (e) {
  erros.push(`Marcar cenas texto: ${e.message}`);
}

// 5. Criar cena de texto final (tela final em Creepster)
try {
  if (data._opcao.texto_final_tela && data._opcao.texto_final_tela.trim().length > 0) {
    // Buscar maior ordem atual das cenas aprovadas
    const cenasOrdem = await this.helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/rest/v1/cenas?video_id=eq.${data._videoId}&opcao_id=is.null&select=ordem&order=ordem.desc&limit=1`,
      headers: { 'apikey': apiKey, 'Authorization': `Bearer ${apiKey}` }
    });
    const proximaOrdem = (cenasOrdem && cenasOrdem.length > 0 ? cenasOrdem[0].ordem : 0) + 1;

    await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/rest/v1/cenas`,
      headers,
      body: {
        video_id: data._videoId,
        opcao_id: null,
        numero: 'final',
        ordem: proximaOrdem,
        narracao: data._opcao.texto_final_tela,
        tipo_cena: 'texto',
        duracao_estimada: 3,
        transicao_entrada: 'dip_to_black',
        imagem_status: 'aprovada',
        tts_status: 'aprovada',
        efeito_status: 'aprovada',
        video_status: 'aprovada'
      }
    });
  }
} catch (e) {
  erros.push(`Criar cena texto final: ${e.message}`);
}

return [{
  json: {
    success: erros.length === 0,
    video_id: data._videoId,
    modulo_atual: '03',
    erros
  }
}];

